window.SESSIONS = [{"id":"2026-07-08-3-00-pm-neuromuscular-alterations-in-adolescent-youth-performing-resi","date":"2026-07-08","day":"Wed","start":"3:00 PM","end":"3:50 PM","category":"Research Lecture","title":"Neuromuscular Alterations in Adolescent Youth Performing Resistance Exercise","presenter":"Ashley Herda, PhD, CPSS,*D, CSCS,*D, FNSCA","topics":"Research & Education","desc":"Identify adolescent adaptations to resistance exercise. Provide examples for practical application to various sport and age groups.","sponsor":"","personal":false},{"id":"2026-07-08-4-00-pm-the-use-of-computer-programming-in-sport","date":"2026-07-08","day":"Wed","start":"4:00 PM","end":"4:50 PM","category":"Research Lecture","title":"The Use of Computer Programming in Sport","presenter":"Chad Smith, PhD, CSCS","topics":"Research & Education; Sport Science & Training Efficiency","desc":"Describe the advantages of using computer programming in sport science as technology continues to evolve. Compare and contrast MATLAB, Python, and R in terms of their sport science applications.","sponsor":"","personal":false},{"id":"2026-07-08-5-00-pm-weight-management-strategies-for-weight-category-athletes","date":"2026-07-08","day":"Wed","start":"5:00 PM","end":"5:50 PM","category":"Research Lecture","title":"Weight Management Strategies for Weight Category Athletes","presenter":"Andrew Jagim, PhD, CSCS","topics":"Research & Education","desc":"Know the steps in the weight certification process for wrestling and how this influences weight loss trends vs. other weight-category combat sport athletes. Understand the health and safety concerns of excessive weight cutting and frequent weight cycling. Know the evidence-based guidelines for safe and effective weight-reduction strategies.","sponsor":"","personal":false},{"id":"2026-07-08-2-00-pm-tactical-culinary-nutrition","date":"2026-07-08","day":"Wed","start":"2:00 PM","end":"2:50 PM","category":"Research","title":"Tactical Culinary Nutrition","presenter":"Drew Gonzalez, PhD, CSCS, TSAC-F","topics":"Research & Education; Nutrition & Supplementation","desc":"Identify common nutrition barriers among tactical personnel (shift work, low fruit/vegetable intake, limited food access, minimal cooking experience) and how they affect performance, recovery, and readiness. Apply a food-first framework to on-duty and off-duty meal planning, emphasizing foundational culinary skills (basic cooking techniques, protein prep, fast produce integration). Implement practical coaching strategies for teaching cooking as a performance skill — simple recipe instruction, station-friendly meal-prep, and grab-and-go fueling templates.","sponsor":"","personal":false},{"id":"2026-07-08-2-00-pm-solving-the-hamstring-puzzle","date":"2026-07-08","day":"Wed","start":"2:00 PM","end":"3:50 PM","category":"Workshop","title":"Solving the Hamstring Puzzle","presenter":"Boo Schexnayder, MEd","topics":"Injury Prevention, Rehab, & Return to Performance; Applied Physiology & Biomechanics","desc":"","sponsor":"Sponsored by Perform Better","personal":false},{"id":"2026-07-08-2-00-pm-training-the-foot-core-fascia-system-for-athletic-efficiency","date":"2026-07-08","day":"Wed","start":"2:00 PM","end":"3:50 PM","category":"Workshop","title":"Training the Foot-Core-Fascia System for Athletic Efficiency","presenter":"Emily Splichal, PhD","topics":"Injury Prevention, Rehab, & Return to Performance; Applied Physiology & Biomechanics","desc":"Understand the neuromechanical relationship between the foot, core, and fascial lines in athletic movement. Explore how gravity, ground reaction forces, and sensory input shape motor control and efficiency. Learn practical strategies to activate and strengthen the foot–core connection using barefoot, textured, and fascial-based methods. Experience drills to enhance elastic recoil, dynamic stability, and fascial sequencing for explosive movement. Integrate sensory and fascial concepts into existing strength, conditioning, and recovery programs.","sponsor":"","personal":false},{"id":"2026-07-08-2-00-pm-single-leg-training-the-performance-blueprint","date":"2026-07-08","day":"Wed","start":"2:00 PM","end":"3:50 PM","category":"Workshop","title":"Single-Leg Training: The Performance Blueprint","presenter":"Matt Ibrahim, MS, CSCS","topics":"Applied Physiology & Biomechanics; Program Design & Practical Application","desc":"Build a better understanding and improve your ability to coach, program, and execute knee-dominant, hip-dominant, and combined single-leg training exercises. Develop sound exercise selection and program design strategies through critical thinking. Review and apply practical single-leg training exercise progressions, regressions, and lateralizations.","sponsor":"","personal":false},{"id":"2026-07-08-4-00-pm-pelvic-health-for-the-athlete-beyond-the-basics","date":"2026-07-08","day":"Wed","start":"4:00 PM","end":"5:50 PM","category":"Workshop","title":"Pelvic Health for the Athlete: Beyond the Basics","presenter":"Rachel Selman, PT, DPT, CSCS, CPSS","topics":"Injury Prevention, Rehab, & Return to Performance; Population Specific Training; Program Design & Practical Application","desc":"Describe the function and musculature of the pelvic floor muscles in sport performance. Program dynamic pelvic floor exercise in standing, jumping, and running positions. Determine based on athlete symptoms whether performance goals are being limited by pelvic floor deficiencies.","sponsor":"","personal":false},{"id":"2026-07-08-4-00-pm-from-prep-to-pro-gridiron-performance-panel","date":"2026-07-08","day":"Wed","start":"4:00 PM","end":"5:50 PM","category":"Workshop","title":"From Prep to Pro: Gridiron Performance Panel","presenter":"Scott Bennett; Christian Brown; Jim Davis; Boyd Epley; Colin Kenyon; Justin Lovett","topics":"Program Design & Practical Application","desc":"","sponsor":"Workshop sponsored by Football SIG and College Coaches PDG. Moderated by Justin Lima.","personal":false},{"id":"2026-07-09-9-00-am-nsca-foundation-data-blitz","date":"2026-07-09","day":"Thu","start":"9:00 AM","end":"9:50 AM","category":"Lecture (Research)","title":"NSCA Foundation Data Blitz","presenter":"Moderator: Dr. Susie Reiner (NSCA Foundation Grant Committee Chair). Presenters: Nick Kuhlman; Sarah Lanham; Zach Gillen; Jennifer Rivera","topics":"Research & Education","desc":"Fast-paced 5-minute research presentation session featuring NSCA Foundation grant-funded research, followed by Q&A. (1) Nick Kuhlman — Effects of collagen peptide supplementation on bone turnover, cytokine, and inflammatory markers in female distance runners. (2) Sarah Lanham — Impact of on-duty endurance exercise on firefighter neuromuscular function. (3) Zach Gillen — Sex-related differences in muscle growth and development across puberty. (4) Jennifer Rivera — Effects of cold-water immersion timing on recovery and athletic performance.","sponsor":"NSCA Foundation grant-funded research","personal":false},{"id":"2026-07-09-10-00-am-nsca-update-and-keynote-from-strength-to-sport-science-the-e","date":"2026-07-09","day":"Thu","start":"10:00 AM","end":"11:20 AM","category":"Lecture (Research)","title":"NSCA Update and KEYNOTE: From Strength to Sport Science — The Evolving Art of Program Design","presenter":"William Kraemer, PhD, CSCS,*D, FNSCA","topics":"Program Design & Practical Application; Sport Science & Training Efficiency","desc":"Academia — understand scientific principles underlying training methodologies. Coach — implement strength & conditioning programs for athletes. Practitioner/PT — adapt training variations for different fitness levels and goals. Sports Med — assess recovery strategies within program design. Sports Science — utilize analytics to optimize training decisions. Tactical — balance performance, durability, and recovery in training plans.","sponsor":"Conference Keynote","personal":false},{"id":"2026-07-09-2-00-pm-gary-dudley-lecture-the-warfighter-tactical-athlete-as-a-huma","date":"2026-07-09","day":"Thu","start":"2:00 PM","end":"2:50 PM","category":"Lecture (Research)","title":"Gary Dudley Lecture: The Warfighter Tactical Athlete as a Human Stress Model — Physiological Training Implications for the S&C Professional","presenter":"Brad Nindl, PhD","topics":"Population Specific Training; Applied Physiology & Biomechanics","desc":"Introduce the tactical environment as a natural laboratory where prolonged load, sleep restriction, underfeeding, and psychological stress converge — and how these stress muscle and endocrine systems in adaptation/maladaptation patterns. Discuss how strength and lean tissue behave under prolonged operational strain. Translate mechanistic and field insights into applied takeaways: load management, nutrition/energy availability, planned heavy exposures, minimal effective dose, and simple field-accessible monitoring.","sponsor":"Named Lecture (Gary Dudley)","personal":false},{"id":"2026-07-09-2-00-pm-sport-science-in-college-football-current-research-and-future","date":"2026-07-09","day":"Thu","start":"2:00 PM","end":"2:50 PM","category":"Lecture (Research)","title":"Sport Science in College Football — Current Research and Future Directions","presenter":"Quincy Johnson, CSCS*D, CPT*D","topics":"Sport Science & Training Efficiency; Research & Education","desc":"Basis of sport science research in football and early discoveries. Current state of research, discovery, and sport science in football. The Jayhawk Athletic Performance Laboratory's flagship project Gridiron Performance: The Science of Football and how it contributes to the future of scientific discovery and innovation.","sponsor":"","personal":false},{"id":"2026-07-09-2-00-pm-from-athletes-to-older-adults-ability-of-dietary-supplements-","date":"2026-07-09","day":"Thu","start":"2:00 PM","end":"2:50 PM","category":"Lecture (Research)","title":"From Athletes to Older Adults: Ability of Dietary Supplements to Influence Neuromuscular Function","presenter":"Joshua Keller, CSCS","topics":"Research & Education","desc":"Explain how muscle oxygenation and blood flow influence neuromuscular function across the lifespan, and evaluate how dietary strategies affect these processes. Identify evidence-based dietary supplements/nutritional components most likely to improve neuromuscular performance at different stages of life. Assess realistic expectations for performance and functional outcomes from dietary supplementation in athletic and aging populations.","sponsor":"","personal":false},{"id":"2026-07-09-3-00-pm-lift-jump-thrive-what-every-woman-should-know-about-bone-heal","date":"2026-07-09","day":"Thu","start":"3:00 PM","end":"3:50 PM","category":"Lecture (Research)","title":"Lift, Jump, Thrive: What Every Woman Should Know About Bone Health and Exercise","presenter":"Kristina Kendall, PhD, CSCS","topics":"Research & Education; Population Specific Training","desc":"Explain how mechanical loading stimulates osteogenic responses in girls and women and evaluate effectiveness of different exercise types for developing peak bone mass. Compare effects of various sports on bone mineral density in girls and young women. Summarize evidence-based exercise strategies that promote peak bone mass and preserve bone density during peri- and post-menopause — including specific recommendations for high-impact loading, multidirectional activity, and progressive resistance training.","sponsor":"","personal":false},{"id":"2026-07-09-4-00-pm-the-lifelong-impact-of-strength-training-on-cardiometabolic-h","date":"2026-07-09","day":"Thu","start":"4:00 PM","end":"4:50 PM","category":"Lecture (Research)","title":"The Lifelong Impact of Strength Training on Cardiometabolic Health","presenter":"Alyssa Parten, CSCS,*D, NSCA-CPT","topics":"Research & Education","desc":"Evaluate current scientific evidence demonstrating how resistance training promotes cardiovascular and metabolic health. Compare and contrast cardiovascular responses and long-term adaptations elicited by resistance training vs. endurance exercise. Examine how resistance training mitigates age- and hormone-related declines in cardiovascular health in women across the lifespan.","sponsor":"","personal":false},{"id":"2026-07-09-12-00-pm-doing-it-on-the-fly-making-adjustments-to-training-in-the-mo","date":"2026-07-09","day":"Thu","start":"12:00 PM","end":"12:50 PM","category":"Workshop","title":"Doing It on the Fly — Making Adjustments to Training in the Moment Based on How Your Crew Walks In","presenter":"Cole Hergott, MS, CPSS, CSCS,*D, NSCA-CPT, RSCC","topics":"Program Design & Practical Application","desc":"Learn how to make simple changes to programs/exercises based on various injuries/niggles. Make adjustments to full team sessions based on a tough or easy training day. Learn how to do speed & power training when athletes present with pain or injuries.","sponsor":"Hands-on","personal":false},{"id":"2026-07-09-1-00-pm-applied-shoulder-mechanics-for-overhead-athletes","date":"2026-07-09","day":"Thu","start":"1:00 PM","end":"1:50 PM","category":"Workshop","title":"Applied Shoulder Mechanics for Overhead Athletes","presenter":"Luke Bradford, CSCS","topics":"Program Design & Practical Application; Applied Physiology & Biomechanics; Injury Prevention, Rehab, & Return to Performance","desc":"Articulate the anatomy of the shoulder complex and contributions to healthy joint motions. Acquire foundational skills to improve overall shoulder function. Apply knowledge of shoulder mechanics through common push and pull movements.","sponsor":"Hands-on","personal":false},{"id":"2026-07-09-2-00-pm-lessons-learned-from-rtp-that-have-helped-me-become-a-better-","date":"2026-07-09","day":"Thu","start":"2:00 PM","end":"2:50 PM","category":"Workshop","title":"Lessons Learned from RTP That Have Helped Me Become a Better Performance Coach","presenter":"Erik Hernandez, CSCS, RSCC*D","topics":"Injury Prevention, Rehab, & Return to Performance; Program Design & Practical Application","desc":"Bring awareness to joints/tissues above and below symptoms and how they may factor into common symptoms. Connect how some favorite exercises may be a source of issues. Design programs for rehab that are similar to performance programs.","sponsor":"Hands-on","personal":false},{"id":"2026-07-09-3-00-pm-program-design-implementation-of-plyometrics-in-the-private-s","date":"2026-07-09","day":"Thu","start":"3:00 PM","end":"3:50 PM","category":"Workshop","title":"Program Design & Implementation of Plyometrics in the Private Sector","presenter":"Natalie Kollars","topics":"Injury Prevention, Rehab, & Return to Performance; Applied Physiology & Biomechanics","desc":"","sponsor":"Hands-on sponsored by Perform Better","personal":false},{"id":"2026-07-09-4-00-pm-weightlifting-technical-corrections-and-feedback-strategies","date":"2026-07-09","day":"Thu","start":"4:00 PM","end":"4:50 PM","category":"Workshop","title":"Weightlifting: Technical Corrections and Feedback Strategies","presenter":"Kyle Pierce, CSCS; Paul Comfort, PhD, CSCS,*D, FNSCA; Carissa Gordon","topics":"Applied Physiology & Biomechanics; Program Design & Practical Application","desc":"Recognition of common technical errors in Olympic-style lifts and variations. Identification of underlying causes of common technical errors. Understanding appropriate correction strategies for common technical errors.","sponsor":"Hands-on","personal":false},{"id":"2026-07-09-9-00-am-abstract-podium-presentations-session-1","date":"2026-07-09","day":"Thu","start":"9:00 AM","end":"10:00 AM","category":"Abstract Podium Presentations","title":"Abstract Podium Presentations (Session 1)","presenter":"Justen Stoner; Jacob Rintoul; Jerry Chen; Kornkanok Sophonsakulrat","topics":"Research & Education","desc":"9:00 AM — Justen Stoner: Carbohydrate dosing strategies for elite athletes. 9:15 AM — Jacob Rintoul: Creatine, HMB, strength, and well-being. 9:30 AM — Jerry Chen: Preliminary study of shoulder flexion mobility and swim start performance. 9:45 AM — Kornkanok Sophonsakulrat: Influence of an 8-week training intervention on muscle cross-sectional area.","sponsor":"","personal":false},{"id":"2026-07-09-12-00-pm-abstract-podium-presentations-session-2","date":"2026-07-09","day":"Thu","start":"12:00 PM","end":"12:50 PM","category":"Abstract Podium Presentations","title":"Abstract Podium Presentations (Session 2)","presenter":"Julian Belardo; Paulo Engelke; Lachlan Maudsley; Hannah Eberhardt","topics":"Research & Education","desc":"12:00 PM — Julian Belardo: Relationship between weekly GPS-derived external training load and CMJ performance. 12:15 PM — Paulo Engelke: Force–time signatures of reduced, maintained, and increased countermovement jump height. 12:30 PM — Lachlan Maudsley: Seasonal stretch-shortening cycle changes in Division I basketball players. 12:45 PM — Hannah Eberhardt: Energy availability and muscle quality in Air Force ROTC cadets.","sponsor":"","personal":false},{"id":"2026-07-09-1-00-pm-abstract-podium-presentations-session-3","date":"2026-07-09","day":"Thu","start":"1:00 PM","end":"1:50 PM","category":"Abstract Podium Presentations","title":"Abstract Podium Presentations (Session 3)","presenter":"Emma Worley; Andrew Fields; Dakota Tiede; Michael Mydlo","topics":"Research & Education","desc":"1:00 PM — Emma Worley: Home and away game external demands in NCAA DI football. 1:15 PM — Andrew Fields: Reliability of weekly heart rate variability averages. 1:30 PM — Dakota Tiede: Lengthened partials vs. full ROM on thigh muscle hypertrophy. 1:45 PM — Michael Mydlo: Nordic force normalization method agreement.","sponsor":"","personal":false},{"id":"2026-07-09-12-00-pm-abstract-poster-session-a","date":"2026-07-09","day":"Thu","start":"12:00 PM","end":"1:30 PM","category":"Abstract Poster Session (non-podium)","title":"Abstract Poster Session A","presenter":"(Multiple presenters — details on-site)","topics":"Research & Education","desc":"Poster session — individual abstracts/presenters not enumerated on the schedule page.","sponsor":"","personal":false},{"id":"2026-07-09-2-00-pm-abstract-poster-session-b","date":"2026-07-09","day":"Thu","start":"2:00 PM","end":"3:30 PM","category":"Abstract Poster Session (non-podium)","title":"Abstract Poster Session B","presenter":"(Multiple presenters — details on-site)","topics":"Research & Education","desc":"Poster session — individual abstracts/presenters not enumerated on the schedule page.","sponsor":"","personal":false},{"id":"2026-07-10-10-30-am-performance-and-belonging-the-psychosocial-architecture-of-y","date":"2026-07-10","day":"Fri","start":"10:30 AM","end":"11:20 AM","category":"Lecture (Research)","title":"Performance and Belonging: The Psychosocial Architecture of Youth Athlete Success","presenter":"Jackson Stone","topics":"Research & Education","desc":"Quantify and compare predictive validity of wellbeing and physiological readiness metrics in youth athletes. Differentiate three psychosocial archetypes and identify tailored management responses for each. Integrate Self-Determination Theory, Win Well, and LTAD principles into weekly monitoring systems. Design monitoring frameworks that embed psychosocial data ethically and efficiently. Apply targeted interventions that leverage belongingness to sustain motivation and performance.","sponsor":"Sponsored by ASCA","personal":false},{"id":"2026-07-10-1-00-pm-lost-for-words-in-search-of-our-coaching-voice","date":"2026-07-10","day":"Fri","start":"1:00 PM","end":"1:50 PM","category":"Lecture (Research)","title":"Lost for Words — In Search of Our Coaching Voice","presenter":"Nick Winkelman, PhD, CSCS, NSCA-CPT","topics":"Business & Professional Growth; Research & Education","desc":"Difference between and definitions for knowledge of what (to coach) and knowledge of how (to coach). Difference between and definitions for internal vs. external cueing. Evidence-based models for the creation and curation of effective language for teaching movement.","sponsor":"Sponsored by Gatorade","personal":false},{"id":"2026-07-10-2-00-pm-innovative-teaching-methods-for-developing-an-effective-stren","date":"2026-07-10","day":"Fri","start":"2:00 PM","end":"2:50 PM","category":"Lecture (Research)","title":"Innovative Teaching Methods for Developing an Effective Strength & Conditioning Internship Curriculum","presenter":"Terrie McNamara, PhD, CSCS; MaryKate Feit, PhD, CSCS,*D, TSAC-F, RSCC*D","topics":"Business & Professional Growth; Research & Education","desc":"Evidence-based teaching methods for creating effective learning experiences. Key components of a well-rounded internship program to maximize learning while meeting CASCE internship requirements. Enhance intern engagement and motivation using Self Determination Theory and sources of self-efficacy.","sponsor":"","personal":false},{"id":"2026-07-10-2-00-pm-heated-resistance-exercise","date":"2026-07-10","day":"Fri","start":"2:00 PM","end":"2:50 PM","category":"Lecture (Research)","title":"Heated Resistance Exercise","presenter":"Luke Pryor, PhD, ATC, CSCS","topics":"Research & Education; Sport Science & Training Efficiency","desc":"Understand the risks associated with heated resistance exercise and mitigation strategies. Describe the health, hypertrophy, and muscular performance benefits of heated resistance exercise. Select evidence-based acute program variables for implementation of heated resistance exercise.","sponsor":"","personal":false},{"id":"2026-07-10-3-00-pm-michael-h-stone-sport-science-lecture-statistics-are-we-too-d","date":"2026-07-10","day":"Fri","start":"3:00 PM","end":"3:50 PM","category":"Lecture (Research)","title":"Michael H Stone Sport Science Lecture: Statistics — Are We Too Dependent?","presenter":"Michael H Stone, PhD, CSCS,*D, FNSCA","topics":"Sport Science & Training Efficiency; Research & Education","desc":"Complex statistical processes are not always necessary, particularly in sport science. Most sport science is exploratory in nature, primarily due to small subject numbers. Necessary to educate researchers, practitioners, reviewers, and editors as to the worth of exploratory studies.","sponsor":"Named Lecture (Michael H Stone Sport Science Lecture)","personal":false},{"id":"2026-07-10-3-00-pm-discovering-your-unknown-superpower-writing-for-professional-","date":"2026-07-10","day":"Fri","start":"3:00 PM","end":"3:50 PM","category":"Lecture (Research)","title":"Discovering Your Unknown Superpower: Writing for Professional Journals","presenter":"Tom Cormier, MS, CSCS*D, CSPS,*D, NSCA-CPT,*D","topics":"Business & Professional Growth; Research & Education","desc":"Uncover and explore your potential talent for producing content. Learn the steps to writing once motivation is there. Publication process and keys for success.","sponsor":"","personal":false},{"id":"2026-07-10-3-00-pm-testing-and-training-for-hamstring-strain-injury-risk","date":"2026-07-10","day":"Fri","start":"3:00 PM","end":"3:50 PM","category":"Lecture (Research)","title":"Testing and Training for Hamstring Strain Injury Risk","presenter":"Nicholas Ripley, PhD, CSCS,*D, RSCC","topics":"Research & Education; Injury Prevention, Rehab, & Return to Performance","desc":"Identify primary risk factors for hamstring strain injuries and appropriate assessment methods. Explore field-based strategies for reducing risk. Highlight gym-based strategies for reducing risk and provide resistance training recommendations.","sponsor":"","personal":false},{"id":"2026-07-10-4-00-pm-fueling-needs-energy-expenditure-and-macronutrient-needs-of-h","date":"2026-07-10","day":"Fri","start":"4:00 PM","end":"4:50 PM","category":"Lecture (Research)","title":"Fueling Needs, Energy Expenditure, and Macronutrient Needs of High School Athletes","presenter":"Chad Kerksick, PhD, CSCS, NSCA-CPT, FNSCA","topics":"Research & Education; Nutrition & Supplementation","desc":"Identify components that comprise total daily energy expenditure and energy availability. Describe factors that impact carbohydrate needs. Outline key factors that influence protein needs. Develop a hydration plan. Identify key factors that impact fueling needs.","sponsor":"","personal":false},{"id":"2026-07-10-8-30-am-how-hard-should-you-train-to-maximize-muscular-adaptations","date":"2026-07-10","day":"Fri","start":"8:30 AM","end":"9:20 AM","category":"Lecture","title":"How Hard Should You Train to Maximize Muscular Adaptations","presenter":"Brad Schoenfeld, PhD, CSPS,*D, CSCS,*D, NSCA-CPT,*D, FNSCA","topics":"Sport Science & Training Efficiency; Program Design & Practical Application","desc":"Design resistance training programs to best manipulate intensity of effort for optimizing muscular adaptations. Describe how certain covariates can influence optimal prescription for intensity of effort.","sponsor":"","personal":false},{"id":"2026-07-10-2-00-pm-big-strength-small-muscles-unraveling-the-muscle-quality-para","date":"2026-07-10","day":"Fri","start":"2:00 PM","end":"2:50 PM","category":"Lecture","title":"Big Strength, Small Muscles: Unraveling the Muscle Quality Paradox","presenter":"Matt Stock, PhD, CSCS, FNSCA","topics":"Applied Physiology & Biomechanics; Population Specific Training; Program Design & Practical Application","desc":"Understand the distinction between muscle mass and muscle quality and their independent contributions to strength and health. Identify how neuromuscular factors and intramuscular fat influence muscle quality and functional outcomes. Evaluate the implications of prioritizing muscle quality over mass in clinical and rehabilitation settings.","sponsor":"","personal":false},{"id":"2026-07-10-9-30-am-training-the-kinematics-of-linear-speed-development","date":"2026-07-10","day":"Fri","start":"9:30 AM","end":"10:20 AM","category":"Workshop","title":"Training the Kinematics of Linear Speed Development","presenter":"Nick Brattain, CSCS","topics":"Applied Physiology & Biomechanics; Program Design & Practical Application","desc":"Identify optimal center of gravity, postural angles, and projection with respect to athlete development. Address movement technical analysis and manipulation. Design a program to improve athletic performance.","sponsor":"Hands-on","personal":false},{"id":"2026-07-10-9-30-am-navigating-casce-accreditation-interactive-workshop","date":"2026-07-10","day":"Fri","start":"9:30 AM","end":"11:20 AM","category":"Workshop","title":"Navigating CASCE Accreditation: Interactive Workshop","presenter":"(Not listed on schedule)","topics":"","desc":"Practical guidance for program directors, faculty, and staff working through CASCE accreditation: self-study development, site visit preparation, and final review.","sponsor":"Interactive Workshop — accreditation-process focused","personal":false},{"id":"2026-07-10-10-30-am-kettlebell-training-for-sport-performance","date":"2026-07-10","day":"Fri","start":"10:30 AM","end":"11:20 AM","category":"Workshop","title":"Kettlebell Training for Sport Performance","presenter":"Andrew Mitchell, CSCS, RSCC","topics":"Applied Physiology & Biomechanics; Program Design & Practical Application","desc":"Swing, clean, and snatch progression with single bell and double kettlebell programming. Benefits and practicality of kettlebell training vs. barbell training for strength, power, speed across sports. Parallels between kettlebells and common sport movement. Benefits and drawbacks of kettlebell programming for short- and long-term programming and around resource/budget constraints.","sponsor":"Hands-on","personal":false},{"id":"2026-07-10-1-00-pm-bridge-the-gap-practical-the-10-x-10-protocol-for-performance","date":"2026-07-10","day":"Fri","start":"1:00 PM","end":"1:50 PM","category":"Workshop","title":"Bridge the Gap Practical: The 10 x 10 Protocol for Performance and Return to Play","presenter":"Derek Hansen, MA, CSCS","topics":"Applied Physiology & Biomechanics; Injury Prevention, Rehab, & Return to Performance","desc":"Identify planning, equipment, and implementation requirements for the 10x10 protocol. Outline key parameters for using the 10x10 protocol to enhance sprint speed, repeat sprint ability, and general conditioning. Overview of using the 10x10 protocol to rehabilitate lower body injuries (hamstring strains, achilles and calf injuries, ankle/knee/hip).","sponsor":"Hands-on","personal":false},{"id":"2026-07-10-2-00-pm-bridge-the-gap-practical-build-superior-athletes-and-clients-","date":"2026-07-10","day":"Fri","start":"2:00 PM","end":"2:50 PM","category":"Workshop","title":"Bridge the Gap Practical: Build Superior Athletes and Clients Utilizing Strongman Methodology","presenter":"Heidi Campo, CSCS,*D, NSCA-CPT,*D; Chris Slater, MEd, CSCS","topics":"Program Design & Practical Application","desc":"Advantages of using strongman training with teams or clients. How to integrate strongman methodology into programming. Hands-on workshop of proper techniques, cueing, and coaching.","sponsor":"Hands-on","personal":false},{"id":"2026-07-10-8-30-am-abstract-podium-presentations-session-1","date":"2026-07-10","day":"Fri","start":"8:30 AM","end":"9:20 AM","category":"Abstract Podium Presentations","title":"Abstract Podium Presentations (Session 1)","presenter":"Noelle Saine; Scott Brau; Nestor Urrea; Payton Miller","topics":"Research & Education","desc":"8:30 AM — Noelle Saine: Classification analysis of sport using countermovement jump metrics. 8:45 AM — Scott Brau: Recovery status and accuracy estimating repetitions-in-reserve. 9:00 AM — Nestor Urrea: Training load at MD-2 and MD-1 predicts match outcome. 9:15 AM — Payton Miller: Aerobic capacity is associated with lower depression and anxiety in firefighters.","sponsor":"","personal":false},{"id":"2026-07-10-9-30-am-abstract-podium-presentations-session-2","date":"2026-07-10","day":"Fri","start":"9:30 AM","end":"10:20 AM","category":"Abstract Podium Presentations","title":"Abstract Podium Presentations (Session 2)","presenter":"Jiahao Yang; Pablo Rios-Gallardo; Alayne Thompson; Erica Schafer","topics":"Research & Education","desc":"9:30 AM — Jiahao Yang: Acute effects of various submaximal accentuated eccentric loading protocols. 9:45 AM — Pablo Rios-Gallardo: Strategy shift in pediatric jump mechanics. 10:00 AM — Alayne Thompson: Lower body strength changes in postmenopausal females after training. 10:15 AM — Erica Schafer: Physical activity and psychological health in female tactical athletes.","sponsor":"","personal":false},{"id":"2026-07-10-10-30-am-abstract-podium-presentations-session-3","date":"2026-07-10","day":"Fri","start":"10:30 AM","end":"11:20 AM","category":"Abstract Podium Presentations","title":"Abstract Podium Presentations (Session 3)","presenter":"Dakota Dronet; Benjamin Doyle; Andrew Veith; Tiffany Adams","topics":"Research & Education","desc":"10:30 AM — Dakota Dronet: Effects of summer professional soccer on collegiate female soccer performance. 10:45 AM — Benjamin Doyle: Latent subclass modeling of physiological adaptation phenotypes to strength training. 11:00 AM — Andrew Veith: Role of motor units on sudden strength increases. 11:15 AM — Tiffany Adams: Fitness predictors of metabolic risk in firefighters.","sponsor":"","personal":false},{"id":"2026-07-10-1-00-pm-abstract-podium-presentations-session-4","date":"2026-07-10","day":"Fri","start":"1:00 PM","end":"1:50 PM","category":"Abstract Podium Presentations","title":"Abstract Podium Presentations (Session 4)","presenter":"Sarah Deemer; Katie Hirsch; Jay Dawes; Krissy Kendall","topics":"Research & Education","desc":"1:00 PM — Sarah Deemer: Impact of 1 week of curcumin supplementation on biomarker responses to fatiguing back squat exercise in resistance-trained women. 1:15 PM — Katie Hirsch: Characterization of the female hormone profile — application of daily-urine hormone monitoring. 1:30 PM — Jay Dawes: A physical fitness profile of tactical athletes from the southcentral United States. 1:45 PM — Krissy Kendall: Prime time — morning activation and its effects on repeated sprint ability and reaction time in soccer players.","sponsor":"","personal":false},{"id":"2026-07-10-10-30-am-abstract-poster-session-a","date":"2026-07-10","day":"Fri","start":"10:30 AM","end":"12:00 PM","category":"Abstract Poster Session (non-podium)","title":"Abstract Poster Session A","presenter":"(Multiple presenters — details on-site)","topics":"Research & Education","desc":"Poster session — individual abstracts/presenters not enumerated on the schedule page.","sponsor":"","personal":false},{"id":"2026-07-10-12-30-pm-abstract-poster-session-b","date":"2026-07-10","day":"Fri","start":"12:30 PM","end":"2:00 PM","category":"Abstract Poster Session (non-podium)","title":"Abstract Poster Session B","presenter":"(Multiple presenters — details on-site)","topics":"Research & Education","desc":"Poster session — individual abstracts/presenters not enumerated on the schedule page.","sponsor":"","personal":false},{"id":"2026-07-11-11-30-am-keynote-behind-the-curtain-of-strength-conditioning-what-act","date":"2026-07-11","day":"Sat","start":"11:30 AM","end":"12:20 PM","category":"Lecture (Research)","title":"KEYNOTE: Behind the Curtain of Strength & Conditioning — What Actually Matters Across Programming, Coaching, and Career Decisions","presenter":"Brett Bartholomew, MSEd, CSCS","topics":"Population Specific Training; Business & Professional Growth; Sport Science & Training Efficiency","desc":"Identify and discern which S&C methods are truly practical across contexts. Proven examples of strength, speed, and agility programming with minimal budget/equipment. Coaching techniques to build trust with hardest-to-reach athletes; key considerations for budget conversations with administrators. Practical strategies to avoid stagnation, navigate professional pitfalls, and improve long-term earning potential without compromising integrity.","sponsor":"Closing Conference Keynote","personal":false},{"id":"2026-07-11-8-30-am-power-complex-my-pilot-study-on-replacing-cleans-in-the-weigh","date":"2026-07-11","day":"Sat","start":"8:30 AM","end":"9:20 AM","category":"Lecture","title":"Power Complex: My Pilot Study on Replacing Cleans in the Weight Room","presenter":"Justin Lima, PhD, CSCS, RSCC*D","topics":"Program Design & Practical Application; Applied Physiology & Biomechanics","desc":"Describe how the Power Complex serves as an alternative and complementary method for developing explosive power compared to relying solely on the traditional power clean. Identify common technical, physical, and logistical reasons athletes may struggle to perform a traditional power clean in high school team settings. Apply the Power Complex as a progression strategy to improve power development while increasing time efficiency in large-group training environments.","sponsor":"","personal":false},{"id":"2026-07-11-10-30-am-muscle-mass-the-overlooked-link-in-metabolic-flexibility","date":"2026-07-11","day":"Sat","start":"10:30 AM","end":"11:20 AM","category":"Lecture","title":"Muscle Mass: The Overlooked Link in Metabolic Flexibility","presenter":"Hunter Waldman, PhD, CSCS","topics":"Applied Physiology & Biomechanics; Program Design & Practical Application","desc":"Understand the physiological role of muscle mass in metabolic flexibility — its impact on substrate utilization, insulin sensitivity, and energy partitioning. Evaluate the limitations of a cardio-centric approach to metabolic health and recognize how strength training enhances long-term metabolic adaptability. Apply evidence-based strategies to optimize programming and nutrition for improving metabolic flexibility through muscle hypertrophy and resistance training.","sponsor":"","personal":false},{"id":"2026-07-11-8-30-am-embracing-asymmetry-harnessing-natural-movement-patterns-for-","date":"2026-07-11","day":"Sat","start":"8:30 AM","end":"9:20 AM","category":"Workshop","title":"Embracing Asymmetry: Harnessing Natural Movement Patterns for Optimal Performance","presenter":"Adarian Barr, MA","topics":"Applied Physiology & Biomechanics; Program Design & Practical Application","desc":"Define and understand the concept of asymmetry in human movement and its role in supporting efficient, dynamic performance. Explore how natural asymmetries in strength and range of motion enhance resilience and prevent injury. Apply strategies to leverage natural asymmetries to improve strength, range of motion, and overall performance.","sponsor":"Hands-on","personal":false},{"id":"2026-07-11-9-30-am-bracing-for-maximal-lifting","date":"2026-07-11","day":"Sat","start":"9:30 AM","end":"10:20 AM","category":"Workshop","title":"Bracing for Maximal Lifting","presenter":"Richard Ulm, DC, MS, CSCS","topics":"Applied Physiology & Biomechanics","desc":"Biomechanics and anatomy of a proper brace. How to quickly and accurately assess an athlete's bracing strategy. Corrective exercises so coaches can properly teach their athletes how to brace. How to effectively apply a proper brace to maximal lifting for improved performance and fewer injuries.","sponsor":"Hands-on","personal":false},{"id":"2026-07-11-10-30-am-using-breathing-physiology-to-enhance-performance","date":"2026-07-11","day":"Sat","start":"10:30 AM","end":"11:20 AM","category":"Workshop","title":"Using Breathing & Physiology to Enhance Performance","presenter":"Jena Gatses, PT, DPT, LMT SFMA, CSCS","topics":"Applied Physiology & Biomechanics","desc":"Breathwork as a performance multiplier — how controlled breathing enhances strength, endurance, and recovery via oxygen utilization and nervous system regulation. Integrating physiology and breath control — how biomechanics, neuromuscular activation, and metabolic efficiency are influenced by breathing techniques. Practical applications for elite performance — actionable strategies for training, rehabilitation, and competition.","sponsor":"Hands-on","personal":false},{"id":"2026-07-11-8-30-am-abstract-podium-presentations-session-1","date":"2026-07-11","day":"Sat","start":"8:30 AM","end":"9:20 AM","category":"Abstract Podium Presentations","title":"Abstract Podium Presentations (Session 1)","presenter":"Timothy Suchomel; Quincy Johnson; Ran Wang; Paul Baker","topics":"Research & Education","desc":"8:30 AM — Timothy Suchomel: Impulse characteristics of weightlifting derivatives performed with peak power loads. 8:45 AM — Quincy Johnson: The stride project — contributors to athleticism in youth populations. 9:00 AM — Ran Wang: Overcoming squat sticking region — variable resistance vs. eccentric overload. 9:15 AM — Paul Baker: Adipose tissue metabolic responses to acute HIIT in perimenopause.","sponsor":"","personal":false},{"id":"2026-07-11-9-30-am-abstract-podium-presentations-session-2","date":"2026-07-11","day":"Sat","start":"9:30 AM","end":"10:20 AM","category":"Abstract Podium Presentations","title":"Abstract Podium Presentations (Session 2)","presenter":"Alexandru Buga; Nicholas Ripley; Stephen Opskar; Greg Ryan","topics":"Research & Education","desc":"9:30 AM — Alexandru Buga: Exogenous ketosis augments virtual shooting performance pre/post sleep deprivation. 9:45 AM — Nicholas Ripley: Beyond the RSI — is the dynamic rebound index redundant? 10:00 AM — Stephen Opskar: Jump height and job task performance relationship in firefighters. 10:15 AM — Greg Ryan: Anthropometric and performance relationship to stats in 2024 NBA rookies.","sponsor":"","personal":false},{"id":"2026-07-11-10-30-am-abstract-podium-presentations-session-3","date":"2026-07-11","day":"Sat","start":"10:30 AM","end":"11:20 AM","category":"Abstract Podium Presentations","title":"Abstract Podium Presentations (Session 3)","presenter":"Jeremy Ross; Megan Sax van der Weyden; Ty Palmer; John Paul Anders","topics":"Research & Education","desc":"10:30 AM — Jeremy Ross: Multivariate modeling of neuromuscular status in special operations qualification training. 10:45 AM — Megan Sax van der Weyden: Dual task foot patrols alter muscle activity. 11:00 AM — Ty Palmer: Hip strength and postural balance. 11:15 AM — John Paul Anders: Float therapy for occupational stress in law enforcement.","sponsor":"","personal":false},{"id":"2026-07-11-10-00-am-abstract-poster-session-a","date":"2026-07-11","day":"Sat","start":"10:00 AM","end":"11:30 AM","category":"Abstract Poster Session (non-podium)","title":"Abstract Poster Session A","presenter":"(Multiple presenters — details on-site)","topics":"Research & Education","desc":"Poster session — individual abstracts/presenters not enumerated on the schedule page.","sponsor":"","personal":false},{"id":"personal-poster-fri","date":"2026-07-10","day":"Fri","start":"1:00 PM","end":"1:50 PM","category":"My Presentation","title":"★ Your Poster Presentation","presenter":"You (presenting)","topics":"Research & Education","desc":"Your poster presentation. Use the notes field below to keep your abstract, board/easel number, key talking points, and anticipated questions. (Heads-up: you said \"Friday the 7th\" — Friday of the conference is July 10; July 7 is the Tuesday before. Placed on Friday July 10 at 1:00 PM. Tell me if the day/time should change. Friday Poster Session B also runs 12:30–2:00 PM if that's your block.)","sponsor":"Personal — your presentation","personal":true},{"id":"personal-dakota-thu","date":"2026-07-09","day":"Thu","start":"1:30 PM","end":"1:45 PM","category":"My Presentation","title":"★ Dakota Tiede — Podium Presentation (colleague)","presenter":"Dakota Tiede","topics":"Research & Education","desc":"Your colleague Dakota Tiede presents \"Lengthened partials vs. full ROM on thigh muscle hypertrophy\" within the Thursday 1:00–1:50 PM Abstract Podium block (their slot is 1:30 PM). Go support them. (Note: spelled \"Tiede\" on the NSCA program.)","sponsor":"Personal — colleague's presentation","personal":true},{"id":"2026-07-09-12-00-pm-preseason-and-in-season-planning-periodization-and-load-mana","date":"2026-07-09","day":"Thu","start":"12:00 PM","end":"12:50 PM","category":"Lecture","title":"Preseason and In Season Planning, Periodization, and Load Management Strategies for Utilizing GPS Technology","presenter":"Michelle Pifer, CSCS, RSCC*D","topics":"Sport Science & Training Efficiency; Program Design & Practical Application","desc":"Learn methods of planning preseason and in season in conjunction of the practice sessions and physical preparation sessions. How to use wearable technology, amongst other technologies, and use subjective data to provide optimal load management prescriptions during preseason and in season. Best application of this material is to collect ideas, know your environment, and make them apply to your team.","sponsor":"","personal":false},{"id":"2026-07-09-1-00-pm-long-term-athlete-development-the-science-and-art-of-andrago","date":"2026-07-09","day":"Thu","start":"1:00 PM","end":"1:50 PM","category":"Lecture","title":"Long Term Athlete Development: The Science and Art of Andragogy for S&C","presenter":"Brian Gearity, PhD, MBA, ATC, CSCS, RSCC*D, FNSCA; Sara Campbell, PhD, CSCS; Clayton Kuklick, PhD, MA, CSCS","topics":"Population Specific Training; Program Design & Practical Application","desc":"Learn historical and contemporary research and its application within S&C related to adult athletes. Learn applied aspects of coaching up the whole adult athlete from a biopsychosocial perspective. Learn tips and tools for effective coaching, personal training, and the like across diverse adult S&C contexts.","sponsor":"","personal":false},{"id":"2026-07-09-1-00-pm-data-driven-insightsapproaches-to-training-velocity-based-tr","date":"2026-07-09","day":"Thu","start":"1:00 PM","end":"1:50 PM","category":"Lecture","title":"Data Driven Insights/Approaches to Training, Velocity Based Training, Recovery Based Training","presenter":"Jordan Troester, PhD, CSCS","topics":"Sport Science & Training Efficiency; Program Design & Practical Application","desc":"Develop a framework for reverse engineering the needs of athletes. Select the most relevant assessments to inform the training process. Connect testing results to training priorities. Connect the learning loop and evaluate the effect of training methods to assessment results and athlete needs.","sponsor":"","personal":false},{"id":"2026-07-09-1-00-pm-leading-with-a-limp-a-comeback-mindset","date":"2026-07-09","day":"Thu","start":"1:00 PM","end":"1:50 PM","category":"Lecture","title":"Leading with a Limp: A Comeback Mindset","presenter":"Katie Guillory, CPSS, CSCS, RSCC*D","topics":"Injury Prevention, Rehab, & Return to Performance; Population Specific Training","desc":"Using a 5 step S&C model to navigate a personal RTP model that doesn't exist currently for highly active amputees. How to turn resilience into an actionable process, how to uphold standards in the midst of your own storm.","sponsor":"Sponsored by the Women's Committee","personal":false},{"id":"2026-07-09-2-00-pm-pregnancy-with-athletes","date":"2026-07-09","day":"Thu","start":"2:00 PM","end":"2:50 PM","category":"Lecture","title":"Pregnancy with Athletes","presenter":"Amy Moolyk, MSc, CSCS","topics":"Population Specific Training; Research & Education","desc":"Provide an overview of current guidance for pregnancy and athletes. Discuss current research on weightlifting during pregnancy.","sponsor":"","personal":false},{"id":"2026-07-09-3-00-pm-wired-to-win-caffeine-culture-and-mental-health-in-sport","date":"2026-07-09","day":"Thu","start":"3:00 PM","end":"3:50 PM","category":"Lecture","title":"Wired to Win? Caffeine, Culture, and Mental Health in Sport","presenter":"Disa Hatfield, PhD, CSCS,*D, FNSCA","topics":"Research & Education","desc":"","sponsor":"","personal":false},{"id":"2026-07-09-3-00-pm-one-cue-doesnt-fit-all-adapting-coaching-communication-acros","date":"2026-07-09","day":"Thu","start":"3:00 PM","end":"3:50 PM","category":"Lecture","title":"One Cue Doesn't Fit All: Adapting Coaching Communication Across Athletes and Environments","presenter":"Brittany Williams, MSEd, MHFA","topics":"Program Design & Practical Application; Business & Professional Growth","desc":"","sponsor":"Lecture sponsored by the Lift Committee","personal":false},{"id":"2026-07-09-3-00-pm-designing-injury-mitigation-programs-that-athletes-and-coach","date":"2026-07-09","day":"Thu","start":"3:00 PM","end":"3:50 PM","category":"Lecture","title":"Designing Injury Mitigation Programs That Athletes and Coaches Embrace","presenter":"Travis Pollen, PhD","topics":"Injury Prevention, Rehab, & Return to Performance","desc":"Analyze the barriers and facilitators to adopting and implementing injury prevention programs. Integrate stakeholders' perceptions in an iterative approach to designing injury prevention programs. Evaluate the success of injury prevention programs using the RE-AIM framework (Reach, Efficacy/Effectiveness, Adoption, Implementation, Maintenance).","sponsor":"","personal":false},{"id":"2026-07-09-4-00-pm-human-performance-technologies-ai-other-advanced-tools","date":"2026-07-09","day":"Thu","start":"4:00 PM","end":"4:50 PM","category":"Lecture","title":"Human Performance Technologies, AI, & Other Advanced Tools","presenter":"Andy Galpin, PhD, CSCS, NSCA-CPT, FNSCA","topics":"Sport Science & Training Efficiency; Program Design & Practical Application","desc":"Understand what tools & technologies are currently available but poorly understood. Discuss several tools and tech that will be available in the near future. Discuss how to utilize AI tools for effective coaching.","sponsor":"","personal":false},{"id":"2026-07-09-4-00-pm-determining-meaningful-change-in-metrics-that-matter-data-an","date":"2026-07-09","day":"Thu","start":"4:00 PM","end":"4:50 PM","category":"Lecture","title":"Determining Meaningful Change in Metrics that Matter: Data Analysis when N=1","presenter":"Anthony Turner, PhD, CSCS*D","topics":"Sport Science & Training Efficiency","desc":"Understand how to choose a test that informs your practice, filtering out the noisy and redundant metrics. Determine how much trust to have in any single metric and thus how much a score must change by to have confidence that the changes are \"real\". Identify appropriate calculations and formulas for reliability, meaningful change, and measurement error, culminating in a single athlete report.","sponsor":"","personal":false},{"id":"2026-07-10-8-30-am-teaching-progressions-and-cues-for-bounding-exercises","date":"2026-07-10","day":"Fri","start":"8:30 AM","end":"9:20 AM","category":"Lecture","title":"Teaching Progressions and Cues for Bounding Exercises","presenter":"Boo Schexnayder, MEd","topics":"Applied Physiology & Biomechanics; Program Design & Practical Application","desc":"Identify faulty biomechanics in bounding exercises. Employ appropriate cues in the error correction process.","sponsor":"Lecture sponsored by Perform Better","personal":false},{"id":"2026-07-10-9-30-am-inter-limb-asymmetry-should-we-be-chasing-perfect-symmetry-l","date":"2026-07-10","day":"Fri","start":"9:30 AM","end":"10:20 AM","category":"Lecture","title":"Inter-Limb Asymmetry: Should We Be Chasing Perfect Symmetry? Lessons Learned from 10 Years of Data Collection.","presenter":"Chris Bishop, PhD","topics":"Sport Science & Training Efficiency; Injury Prevention, Rehab, & Return to Performance","desc":"This presentation will provide a brief overview of the association between inter-limb asymmetry and athletic performance and injury risk. This presentation will outline some historical issues relating to how inter-limb asymmetry has been used and reported, and why this causes problems for practitioners. This presentation will provide 5 fundamental principles for practitioners to consider so that they can maximize their chances of using asymmetry-related data effectively.","sponsor":"","personal":false},{"id":"2026-07-10-9-30-am-the-vagus-nerve-in-athletic-performance-enhancing-recovery-r","date":"2026-07-10","day":"Fri","start":"9:30 AM","end":"10:20 AM","category":"Lecture","title":"The Vagus Nerve in Athletic Performance: Enhancing Recovery, Resilience, and Movement Through Nervous System Regulation","presenter":"Arianne Missimer, DPT, RD, CSCS","topics":"Applied Physiology & Biomechanics; Injury Prevention, Rehab, & Return to Performance","desc":"Understand the vagus nerve's role in autonomic nervous system regulation and its impact on athletic performance, recovery, and resilience. Learn to identify signs of low vagal tone in athletes and how it influences movement quality, recovery readiness, and injury risk. Gain practical, hands-on techniques to stimulate the vagus nerve through breathwork, movement, and recovery protocols, and integrate these strategies into strength and conditioning programs.","sponsor":"","personal":false},{"id":"2026-07-10-9-30-am-from-college-to-high-school-sc-coach","date":"2026-07-10","day":"Fri","start":"9:30 AM","end":"10:20 AM","category":"Lecture","title":"From College to High School S&C Coach","presenter":"Elton Crochran, CSCS,*D, RSCC","topics":"Business & Professional Growth; Program Design & Practical Application","desc":"Learn day to day at the HS level. Know the difference in HS vs college. Manage your ego at the HS level.","sponsor":"","personal":false},{"id":"2026-07-10-10-30-am-bridge-the-gap-lecture-build-superior-athletes-and-clients-u","date":"2026-07-10","day":"Fri","start":"10:30 AM","end":"11:20 AM","category":"Lecture","title":"Bridge the Gap Lecture: Build Superior Athletes and Clients Utilizing Strongman Methodology","presenter":"Heidi Campo, CSCS,*D, NSCA-CPT,*D; Chris Slater, MEd, CSCS","topics":"Program Design & Practical Application","desc":"Learn about the advantages of using strongman training with your teams or clients. Learn how to integrate strongman methodology into your programming. Hands-on workshop of proper techniques, cueing, and coaching.","sponsor":"","personal":false},{"id":"2026-07-10-10-30-am-fueling-the-gut-the-role-of-the-gut-in-optimizing-athletic-p","date":"2026-07-10","day":"Fri","start":"10:30 AM","end":"11:20 AM","category":"Lecture","title":"Fueling the Gut: The Role of the Gut in Optimizing Athletic Performance","presenter":"Carolyn Stocker, MS, RD, CSCS","topics":"Nutrition & Supplementation","desc":"Explain how the gut microbiome influences energy production, immune function, recovery, and mental well-being in athletes and how nutrition, exercise intensity, stress, sleep, and hydration affect the gut microbiome. Learn Practical Nutritional Strategies for maintaining gut health. Recognize signs of gut imbalance in athletes such as bloating, constipation, digestive discomfort, nausea/vomiting, and mental health.","sponsor":"","personal":false},{"id":"2026-07-10-10-30-am-building-the-rotational-athlete-from-force-production-to-inj","date":"2026-07-10","day":"Fri","start":"10:30 AM","end":"11:20 AM","category":"Lecture","title":"Building The Rotational Athlete - From Force Production to Injury Resilience!","presenter":"Mark Kovacs, PhD, CSCS","topics":"Applied Physiology & Biomechanics; Program Design & Practical Application","desc":"Identify the limiting factors in rotational development from power, to endurance. The balance between rotation and anti-rotation training. Sport specificity vs general training on rotational performance.","sponsor":"","personal":false},{"id":"2026-07-10-1-00-pm-uncovering-the-science-behind-the-advanced-hydration-system","date":"2026-07-10","day":"Fri","start":"1:00 PM","end":"1:50 PM","category":"Lecture","title":"Uncovering the Science Behind the Advanced Hydration System","presenter":"Kris Osterberg, PhD, RD, CSSD; Christina Chu, MS, RD, CSSD, LDN","topics":"Nutrition & Supplementation","desc":"This presentation explores the science behind hydration. Our speakers will examine the key physiological mechanisms—including the role of carbohydrate and electrolytes like sodium—that enable faster fluid absorption and retention in the body. Explain the specific roles sodium, carbohydrates and electrolytes have in optimizing hydration status and performance outcomes. Understand athlete-specific hydration needs by analyzing individual factors such as training intensity, duration, environmental conditions and performance goals. Develop personalized hydration strategies that integrate credible science with real-world training and competition scenarios to maximize athlete performance and recovery.","sponsor":"Lecture sponsored by Gatorade","personal":false},{"id":"2026-07-10-1-00-pm-individualizing-your-athletic-development-program-during-the","date":"2026-07-10","day":"Fri","start":"1:00 PM","end":"1:50 PM","category":"Lecture","title":"Individualizing your Athletic Development Program During the Stages of Growth and Maturation to Build a Robust Youth Athlete","presenter":"Paudie Roche, MSc, CSCS","topics":"Population Specific Training; Program Design & Practical Application","desc":"How a long-term, athlete-centred approach ensures safe, effective, and sustainable development and how this approach should be tailored around all the various load demands placed on the growing body. The nuts and bolts of programming for each stage.","sponsor":"Lecture sponsored by UKSCA","personal":false},{"id":"2026-07-10-2-00-pm-minimum-effective-dose-strength-training-as-the-foundation-o","date":"2026-07-10","day":"Fri","start":"2:00 PM","end":"2:50 PM","category":"Lecture","title":"Minimum Effective Dose: Strength Training as the Foundation of Long-Term Athletic Development","presenter":"Antonio Squillante, PhD, CSCS*D, RSCC*D","topics":"Program Design & Practical Application; Population Specific Training","desc":"Minimum Effective Dose Concept: the lecture provides an in-depth review of the minimum effective dose concept in strength training, emphasizing its significance and applications for athletes across different sports. Program Design Fundamentals: participants will explore essential program design principles, including practical examples and various periodization models to effectively manage training volume and intensity throughout an athlete's development. Case Study: a focused case study featuring elite athletes will illustrate the principles of block periodization, addressing key concepts such as reduced training effect, tapering, and strategies for peaking prior to competition.","sponsor":"","personal":false},{"id":"2026-07-10-4-00-pm-maximizing-athlete-potential-strategies-for-stronger-coach-a","date":"2026-07-10","day":"Fri","start":"4:00 PM","end":"4:50 PM","category":"Lecture","title":"Maximizing Athlete Potential: Strategies for Stronger Coach-Athlete Connections","presenter":"Akeem Robinson, PhD","topics":"Business & Professional Growth; Program Design & Practical Application","desc":"Understand the impact of strong coach-athlete relationships on communication, motivation, and trust, and how these factors contribute to improved performance outcomes. Learn practical techniques for identifying and developing high-performing athletes through personalized coaching strategies and individualized support. Implement leadership approaches that foster a culture of peak performance and excellence in strength and conditioning programs.","sponsor":"","personal":false},{"id":"2026-07-11-9-30-am-bridge-the-gap-lecture-the-10-x-10-protocol-for-performance","date":"2026-07-11","day":"Sat","start":"9:30 AM","end":"10:20 AM","category":"Lecture","title":"Bridge the Gap Lecture: The 10 x 10 Protocol for Performance and Return to Play","presenter":"Derek Hansen, MA, CSCS","topics":"Applied Physiology & Biomechanics; Injury Prevention, Rehab, & Return to Performance","desc":"Identify planning, equipment and implementation requirements for the 10x10 protocol. Outline the key parameters for using the 10x10 protocol to enhance overall sprint speed, repeat sprint ability and general conditioning performance. Provide an overview of how the 10x10 protocol can be used to rehabilitate various lower body injuries, including hamstring strains, achilles and calf injuries and other injuries related to ankles, knees and hips.","sponsor":"","personal":false},{"id":"2026-07-11-9-30-am-rehydration-strategies-cho-triathlon-extreme-endurance","date":"2026-07-11","day":"Sat","start":"9:30 AM","end":"10:20 AM","category":"Lecture","title":"Rehydration Strategies, CHO triathlon & Extreme Endurance","presenter":"Alex Harrison, PhD","topics":"Nutrition & Supplementation","desc":"Design high-performing lowest-risk fuel & hydration plans for endurance. Determine carbohydrate sources and sodium sources per athlete and exercise traits. Critically analyze fuel & hydration products for the validity and relevance of their claims.","sponsor":"","personal":false},{"id":"2026-07-11-10-30-am-the-future-of-training-in-professional-football","date":"2026-07-11","day":"Sat","start":"10:30 AM","end":"11:20 AM","category":"Lecture","title":"The Future of Training in Professional Football","presenter":"Ted Rath","topics":"Program Design & Practical Application; Population Specific Training","desc":"Where is NFL performance headed? Ted explores evolving trends in player development, staff structure, technology integration, and leadership. Attendees will walk away with insight into how professional football's performance landscape is changing — and what that means for the next generation of strength coaches at all levels.","sponsor":"","personal":false}];
